#!/usr/bin/env python3
import os, base64
b64 = ''
path = "lib\\pos\\personalkollen.ts"
path = path.replace("\\\\", os.sep).replace("\\", os.sep)
os.makedirs(os.path.dirname(path), exist_ok=True)
with open(path, "wb") as f:
    f.write(base64.b64decode(b64))
print("Done — git add . && git commit -m \"Fix Personalkollen date filter format\" && vercel --prod")
